def 文件读取 (文件路径:str, 编码:str = "utf-8") -> str:
    """读取文本文件内容。"""
    import os
    try:
        if not os.path.exists(文件路径):
            print(f"错误:文件不存在 - {文件路径}")
            return ""
        with open(文件路径,'r', encoding=编码) as f:
            return f.read()
    except Exception as e:
        print(f"错误:读取文件失败 - {e}")
        return ""

def 文件复制 (源路径:str, 目标路径:str, 覆盖已存在:bool = False) -> bool:
    """复制文件到指定位置。"""
    import os, shutil
    try:
        if not os.path.exists(源路径):
            print(f"错误:源文件不存在 - {源路径}")
            return False
        if os.path.isdir(目标路径):
            目标路径 = os.path.join(目标路径,os.path.basename(源路径))
        if os.path.exists(目标路径) and not 覆盖已存在:
            return False
        shutil.copy2(源路径,目标路径)
        print(f"成功复制:{源路径} -> {目标路径}")
        return True
    except Exception as e:
        print(f"错误:复制失败 - {e}")
        return False

def 文件移动 (源路径:str, 目标路径:str, 覆盖已存在:bool = False) -> bool:
    """移动文件到指定位置。"""
    import os, shutil
    try:
        if not os.path.exists(源路径):
            return False
        if os.path.isdir(目标路径):
            目标路径 = os.path.join(目标路径,os.path.basename(源路径))
        shutil.move(源路径,目标路径)
        return True
    except Exception as e:
        print(f"错误:移动失败 - {e}")
        return False

def 文件删除 (文件路径:str, 允许删除文件夹:bool = False) -> bool:
    """删除文件或文件夹。"""
    import os, shutil
    try:
        if not os.path.exists(文件路径):
            return False
        if os.path.isfile(文件路径):
            os.remove(文件路径)
            return True
        elif 允许删除文件夹:
            shutil.rmtree(文件路径)
            return True
        return False
    except Exception as e:
        print(f"错误:删除失败 - {e}")
        return False

def 文件重命名 (文件路径:str, 新名称:str) -> str:
    """重命名文件,返回新路径。"""
    import os
    try:
        if not os.path.exists(文件路径):
            return ""
        dir_path = os.path.dirname(文件路径)
        新路径 = os.path.join(dir_path, 新名称)
        os.rename(文件路径,新路径)
        return 新路径
    except Exception as e:
        print(f"错误:重命名失败 - {e}")
        return ""

def 文件夹遍历 (文件夹路径:str, 递归:bool = True, 文件类型过滤:str = "") -> list:
    """遍历文件夹获取文件列表。"""
    import os
    try:
        if not os.path.exists(文件夹路径):
            return []
        过滤 = [e.strip().lower() for e in 文件类型过滤.split(";") if e.strip()] if 文件类型过滤 else []
        文件列表 = []
        if 递归:
            for root, dirs, files in os.walk(文件夹路径):
                for f in files:
                    if 过滤:
                        ext = os.path.splitext(f)[1].lower()
                        if not any(ext == e or ext == f".{e.lstrip('*')}" for e in 过滤):
                            continue
                    文件列表.append(os.path.join(root, f))
        else:
            for f in os.listdir(文件夹路径):
                fp = os.path.join(文件夹路径,f)
                if os.path.isfile(fp):
                    文件列表.append(fp)
        return 文件列表
    except Exception as e:
        print(f"错误:遍历失败 - {e}")
        return []

def 文件信息获取 (文件路径:str) -> dict:
    """获取文件详细信息。"""
    import os
    from datetime import datetime
    try:
        if not os.path.exists(文件路径):
            return {}
        s = os.stat(文件路径)
        return {
            "name": os.path.basename(文件路径),
            "size": s.st_size,
            "created_time": datetime.fromtimestamp(s.st_ctime).strftime("%Y-%m-%d %H:%M:%S"),
            "modified_time": datetime.fromtimestamp(s.st_mtime).strftime("%Y-%m-%d %H:%M:%S"),
            "is_file": os.path.isfile(文件路径),
            "is_dir": os.path.isdir(文件路径),
            "extension": os.path.splitext(文件路径)[1],
            "full_path": 文件路径
        }
    except Exception as e:
        print(f"错误:获取信息失败 - {e}")
        return {}

def Excel_写入 (文件路径:str, 数据:list, 工作表名:str = "Sheet1", 写入模式:str = "覆盖", 包含表头:bool = True) -> bool:
    """将数据写入 Excel 文件。"""
    import os
    from openpyxl import Workbook, load_workbook
    try:
        dir_path = os.path.dirname(文件路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        if 写入模式 == "追加" and os.path.exists(文件路径):
            wb = load_workbook(文件路径)
            ws = wb[工作表名] if 工作表名 in wb.sheetnames else wb.create_sheet(工作表名)
        else:
            wb = Workbook()
            ws = wb.active
            ws.title = 工作表名
        if 数据 and isinstance(数据 [0], dict):
            headers = list(数据 [0].keys())
            if 包含表头:ws.append(headers)
            for row in 数据:ws.append([row.get(h) for h in headers])
        else:
            for row in 数据:ws.append(row if isinstance(row, list) else [row])
        wb.save(文件路径)
        wb.close()
        return True
    except Exception as e:
        print(f"错误:写入 Excel 失败 - {e}")
        return False

def Excel_合并 (文件列表:list, 输出路径:str, 合并方式:str = "上下合并", 工作表名:str = "") -> bool:
    """合并多个 Excel 文件。"""
    import os
    from openpyxl import Workbook, load_workbook
    try:
        dir_path = os.path.dirname(输出路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        wb_out = Workbook()
        ws_out = wb_out.active
        for fp in 文件列表:
            if os.path.exists(fp):
                wb = load_workbook(fp, data_only=True)
                ws = wb[工作表名] if 工作表名 in wb.sheetnames else wb.active
                for row in ws.iter_rows(values_only=True):
                    ws_out.append(row)
                wb.close()
        wb_out.save(输出路径)
        wb_out.close()
        return True
    except Exception as e:
        print(f"错误:合并失败 - {e}")
        return False

def Word_读取 (文件路径:str, 读取类型:str = "全文") -> str:
    """读取 Word 文档内容。"""
    import os, json
    from docx import Document
    try:
        if not os.path.exists(文件路径):
            return ""
        doc = Document(文件路径)
        if 读取类型 == "全文":
            return "\n".join([p.text for p in doc.paragraphs])
        elif 读取类型 == "段落列表":
            return json.dumps([p.text for p in doc.paragraphs], ensure_ascii=False)
        elif 读取类型 == "表格列表":
            return json.dumps([[[c.text for c in row.cells] for row in t.rows] for t in doc.tables], ensure_ascii=False)
        return ""
    except Exception as e:
        print(f"错误:读取 Word 失败 - {e}")
        return ""

def Word_写入 (文件路径:str, 内容:str, 写入模式:str = "新建") -> bool:
    """创建或写入 Word 文档。"""
    import os
    from docx import Document
    try:
        dir_path = os.path.dirname(文件路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        doc = Document(文件路径) if 写入模式 == "追加" and os.path.exists(文件路径) else Document()
        for p in 内容.split("\n"):
            doc.add_paragraph(p)
        doc.save(文件路径)
        return True
    except Exception as e:
        print(f"错误:写入 Word 失败 - {e}")
        return False

def Word_模板填充 (模板路径:str, 输出路径:str, 替换数据:dict) -> bool:
    """使用数据填充 Word 模板（使用 {{变量名}} 占位）。"""
    import os
    from docx import Document
    try:
        if not os.path.exists(模板路径):
            return False
        dir_path = os.path.dirname(输出路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        doc = Document(模板路径)
        for para in doc.paragraphs:
            for k, v in 替换数据.items():
                para.text = para.text.replace(f"{{{{{k}}}}}", str(v))
        for table in doc.tables:
            for row in table.rows:
                for cell in row.cells:
                    for k, v in 替换数据.items():
                        cell.text = cell.text.replace(f"{{{{{k}}}}}", str(v))
        doc.save(输出路径)
        return True
    except Exception as e:
        print(f"错误:模板填充失败 - {e}")
        return False

def PDF_读取 (PDF_文件路径:str, 页码范围:str = "") -> str:
    """读取 PDF 文档内容。"""
    from PyPDF2 import PdfReader
    import os
    try:
        if not os.path.exists(PDF_文件路径):
            return ""
        reader = PdfReader(PDF_文件路径)
        if 页码范围 and "-" in 页码范围:
            s, e = map(int, 页码范围.split("-"))
            pages = reader.pages[s-1:min(e, len(reader.pages))]
        else:
            pages = reader.pages
        return "\n".join([p.extract_text() for p in pages])
    except Exception as e:
        print(f"错误:读取 PDF 失败 - {e}")
        return ""

def PDF_合并 (PDF_文件列表:list, 输出路径:str) -> bool:
    """合并多个 PDF 文件。"""
    from PyPDF2 import PdfWriter, PdfReader
    import os
    try:
        dir_path = os.path.dirname(输出路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        writer = PdfWriter()
        for fp in PDF_文件列表:
            if os.path.exists(fp):
                reader = PdfReader(fp)
                for page in reader.pages:
                    writer.add_page(page)
        with open(输出路径,"wb") as f:
            writer.write(f)
        return True
    except Exception as e:
        print(f"错误:合并 PDF 失败 - {e}")
        return False

def 数据清洗 (输入数据:list, 清洗规则:str = "去除空值") -> list:
    """清洗数据列表。规则:去除空值、去重、去除空白、转小写、转大写。"""
    try:
        if not 输入数据:return []
        结果 = 输入数据.copy()
        if 清洗规则 == "去除空值":
            结果 = [x for x in 结果 if x is not None and x != ""]
        elif 清洗规则 == "去重":
            seen = set()
            结果 = [x for x in 结果 if not isinstance(x, (list, dict)) and x not in seen and not seen.add(x) or isinstance(x, (list, dict))]
        elif 清洗规则 == "去除空白":
            结果 = [str(x).strip() if x is not None else x for x in 结果]
        elif 清洗规则 == "转小写":
            结果 = [str(x).lower() if isinstance(x, str) else x for x in 结果]
        elif 清洗规则 == "转大写":
            结果 = [str(x).upper() if isinstance(x, str) else x for x in 结果]
        return 结果
    except Exception as e:
        print(f"错误:数据清洗失败 - {e}")
        return []

def 数据排序 (输入数据:list, 排序字段:str, 排序方式:str = "升序") -> list:
    """对数据进行排序。"""
    try:
        if not 输入数据:return []
        reverse = 排序方式 == "降序"
        if 输入数据 and isinstance(输入数据 [0], dict):
            return sorted(输入数据,key=lambda x: x.get(排序字段,0) or 0, reverse=reverse)
        return sorted(输入数据,reverse=reverse)
    except Exception as e:
        print(f"错误:数据排序失败 - {e}")
        return []

def 数据聚合 (输入数据:list, 分组字段:str, 聚合字段:str, 聚合方式:str = "计数") -> list:
    """对数据进行分组聚合。方式:计数、求和、平均值、最大值、最小值。"""
    try:
        if not 输入数据:return []
        分组 = {}
        for item in 输入数据:
            if isinstance(item, dict):
                k = item.get(分组字段)
                if k not in 分组:分组 [k] = []
                分组 [k].append(item.get(聚合字段))
        结果 = []
        for k, vals in 分组.items():
            if 聚合方式 == "计数": v = len(vals)
            elif 聚合方式 == "求和": v = sum(x for x in vals if isinstance(x, (int, float)))
            elif 聚合方式 == "平均值":
                nums = [x for x in vals if isinstance(x, (int, float))]
                v = sum(nums)/len(nums) if nums else 0
            elif 聚合方式 == "最大值": v = max(x for x in vals if isinstance(x, (int, float))) if any(isinstance(x, (int, float)) for x in vals) else None
            elif 聚合方式 == "最小值": v = min(x for x in vals if isinstance(x, (int, float))) if any(isinstance(x, (int, float)) for x in vals) else None
            else: v = len(vals)
            结果.append({分组字段:k, f"{聚合字段}_{聚合方式}": v})
        return 结果
    except Exception as e:
        print(f"错误:数据聚合失败 - {e}")
        return []

def HTTP_请求 (URL: str, 请求方法:str = "GET", 请求头:dict = None, 请求体:str = "", 超时:int = 30) -> dict:
    """发送 HTTP 请求。"""
    import requests
    try:
        resp = requests.request(method=请求方法.upper(), url=URL, headers=请求头 or {}, data=请求体,timeout=超时)
        return {"status_code": resp.status_code, "headers": dict(resp.headers), "body": resp.text, "success": resp.ok}
    except Exception as e:
        return {"status_code": 0, "error": str(e), "success": False}

def 文件下载 (URL: str, 保存路径:str, 请求头:dict = None, 超时:int = 60) -> bool:
    """下载网络文件。"""
    import os, requests
    try:
        dir_path = os.path.dirname(保存路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        resp = requests.get(URL, headers=请求头 or {}, stream=True, timeout=超时)
        resp.raise_for_status()
        with open(保存路径,'wb') as f:
            for chunk in resp.iter_content(chunk_size=8192):
                f.write(chunk)
        return True
    except Exception as e:
        print(f"错误:下载失败 - {e}")
        return False

def API_调用 (URL: str, 请求方法:str = "GET", 请求头:dict = None, 请求体:dict = None, 超时:int = 30) -> dict:
    """调用 REST API 接口。"""
    import json, requests
    try:
        headers = 请求头 or {}
        headers["Content-Type"] = "application/json"
        resp = requests.request(method=请求方法.upper(), url=URL, headers=headers, data=json.dumps(请求体 or {}, ensure_ascii=False), timeout=超时)
        return {"status_code": resp.status_code, "data": resp.json() if "application/json" in resp.headers.get("Content-Type", "") else resp.text, "success": resp.ok}
    except Exception as e:
        return {"status_code": 0, "error": str(e), "success": False}

def 网页抓取 (URL: str, 选择器:str, 抓取类型:str = "text", 编码:str = "utf-8") -> list:
    """抓取网页内容。"""
    import requests
    from bs4 import BeautifulSoup
    try:
        resp = requests.get(URL, timeout=30)
        resp.raise_for_status()
        soup = BeautifulSoup(resp.text, 'html.parser')
        elements = soup.select(选择器)
        if 抓取类型 == "text":
            return [e.get_text(strip=True) for e in elements]
        elif 抓取类型 == "html":
            return [str(e) for e in elements]
        elif 抓取类型 == "attr" and elements and elements[0].attrs:
            attr = list(elements[0].attrs.keys())[0]
            return [e.get(attr) for e in elements]
        return []
    except Exception as e:
        print(f"错误:网页抓取失败 - {e}")
        return []

def 日期格式化 (日期:str = "", 输入格式:str = "", 输出格式:str = "%Y-%m-%d") -> str:
    """格式化日期字符串。"""
    from datetime import datetime
    try:
        if not 日期:
            dt = datetime.now()
        elif 输入格式:
            dt = datetime.strptime(日期,输入格式)
        else:
            for fmt in ["%Y-%m-%d", "%Y/%m/%d", "%Y-%m-%d %H:%M:%S", "%Y%m%d"]:
                try:
                    dt = datetime.strptime(日期,fmt)
                    break
                except:
                    continue
            else:
                return ""
        return dt.strftime(输出格式)
    except Exception as e:
        print(f"错误:日期格式化失败 - {e}")
        return ""

def 日期计算 (日期:str, 操作:str, 数值:int, 日期格式:str = "%Y-%m-%d") -> str:
    """计算日期加减。"""
    from datetime import datetime, timedelta
    try:
        dt = datetime.strptime(日期,日期格式)
        delta = timedelta(days=数值) if 操作 == "加" else -timedelta(days=数值)
        return (dt + delta).strftime(日期格式)
    except Exception as e:
        print(f"错误:日期计算失败 - {e}")
        return ""

def 时间戳转日期 (时间戳:int, 输出格式:str = "%Y-%m-%d %H:%M:%S") -> str:
    """将时间戳转换为日期字符串。"""
    from datetime import datetime
    try:
        if 时间戳 > 1e12:
            时间戳 /= 1000
        return datetime.fromtimestamp(时间戳).strftime(输出格式)
    except Exception as e:
        print(f"错误:时间戳转换失败 - {e}")
        return ""

def 日期转时间戳 (日期:str, 日期格式:str = "%Y-%m-%d %H:%M:%S") -> int:
    """将日期字符串转换为时间戳。"""
    from datetime import datetime
    try:
        return int(datetime.strptime(日期,日期格式).timestamp())
    except Exception as e:
        print(f"错误:日期转时间戳失败 - {e}")
        return 0

def 图片缩放 (图片路径:str, 输出路径:str, 宽度:int = None, 高度:int = None, 保持比例:bool = True, 缩放比例:float = None) -> bool:
    """缩放图片。"""
    import os
    from PIL import Image
    try:
        if not os.path.exists(图片路径):
            return False
        dir_path = os.path.dirname(输出路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        img = Image.open(图片路径)
        w, h = img.size
        if 缩放比例:
            w, h = int(w * 缩放比例), int(h * 缩放比例)
        elif 宽度 and 高度:
            w, h = 宽度,高度
        elif 宽度:
            h = int(h * 宽度 / w)
            w = 宽度
        elif 高度:
            w = int(w * 高度 / h)
            h = 高度
        img.resize((w, h), Image.Resampling.LANCZOS).save(输出路径)
        return True
    except Exception as e:
        print(f"错误:图片缩放失败 - {e}")
        return False

def 图片裁剪 (图片路径:str, 输出路径:str, 左:int, 上:int, 右:int, 下:int) -> bool:
    """裁剪图片。"""
    import os
    from PIL import Image
