        if not os.path.exists(图片路径):
            return False
        dir_path = os.path.dirname(输出路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        img = Image.open(图片路径)
        img.crop((左,上,右,下)).save(输出路径)
        return True
    except Exception as e:
        print(f"错误:图片裁剪失败 - {e}")
        return False

def 图片格式转换 (图片路径:str, 输出路径:str, 目标格式:str = "PNG", 质量:int = 95, 背景色:str = "#FFFFFF") -> bool:
    """转换图片格式。"""
    import os
    from PIL import Image
    try:
        if not os.path.exists(图片路径):
            return False
        dir_path = os.path.dirname(输出路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        img = Image.open(图片路径)
        if 目标格式.upper() == "JPG" and img.mode in ("RGBA", "LA", "P"):
            bg = Image.new("RGB", img.size, 背景色)
            if img.mode == "P":
                img = img.convert("RGBA")
            bg.paste(img, mask=img.split()[-1] if img.mode == "RGBA" else None)
            img = bg
        img.save(输出路径,目标格式.upper(), quality=质量 if 目标格式.upper() in ["JPG", "JPEG", "WEBP"] else None)
        return True
    except Exception as e:
        print(f"错误:图片格式转换失败 - {e}")
        return False

def 图片水印 (图片路径:str, 输出路径:str, 水印文本:str = "", 水印图片:str = "", 位置:str = "右下角", 透明度:float = 0.5, 字体大小:int = 24, 字体颜色:str = "#FFFFFF") -> bool:
    """给图片添加文字或图片水印。"""
    import os
    from PIL import Image, ImageDraw, ImageFont
    try:
        if not os.path.exists(图片路径):
            return False
        dir_path = os.path.dirname(输出路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        img = Image.open(图片路径).convert("RGBA")
        txt_layer = Image.new("RGBA", img.size, (255, 255, 255, 0))
        draw = ImageDraw.Draw(txt_layer)
        try:
            font = ImageFont.truetype("simhei.ttf", 字体大小)
        except:
            font = ImageFont.load_default()
        w, h = img.size
        tw, th = draw.textbbox((0, 0), 水印文本,font=font)[2:4]
        if 位置 == "右下角":
            pos = (w - tw - 10, h - th - 10)
        elif 位置 == "左下角":
            pos = (10, h - th - 10)
        elif 位置 == "右上角":
            pos = (w - tw - 10, 10)
        elif 位置 == "左上角":
            pos = (10, 10)
        elif 位置 == "居中":
            pos = ((w - tw) // 2, (h - th) // 2)
        else:
            pos = (w - tw - 10, h - th - 10)
        r, g, b = int(字体颜色 [1:3], 16), int(字体颜色 [3:5], 16), int(字体颜色 [5:7], 16)
        draw.text(pos, 水印文本,font=font, fill=(r, g, b, int(255 * 透明度)))
        out = Image.alpha_composite(img, txt_layer)
        out.convert("RGB").save(输出路径)
        return True
    except Exception as e:
        print(f"错误:图片水印失败 - {e}")
        return False

def 图片压缩 (图片路径:str, 输出路径:str, 质量:int = 75, 最大宽度:int = None, 最大高度:int = None) -> bool:
    """压缩图片。"""
    import os
    from PIL import Image
    try:
        if not os.path.exists(图片路径):
            return False
        dir_path = os.path.dirname(输出路径)
        if dir_path and not os.path.exists(dir_path):
            os.makedirs(dir_path, exist_ok=True)
        img = Image.open(图片路径)
        w, h = img.size
        if 最大宽度 and w > 最大宽度:
            h = int(h * 最大宽度 / w)
            w = 最大宽度
        if 最大高度 and h > 最大高度:
            w = int(w * 最大高度 / h)
            h = 最大高度
        if w != img.size[0] or h != img.size[1]:
            img = img.resize((w, h), Image.Resampling.LANCZOS)
        if img.mode in ("RGBA", "LA", "P"):
            img = img.convert("RGB")
        img.save(输出路径,"JPEG", quality=质量,optimize=True)
        return True
    except Exception as e:
        print(f"错误:图片压缩失败 - {e}")
        return False
